    long long tax_multiplier;
};

// Function to solve the problem
vector<long long> solve(long long n_ll, vector<long long> prices, vector<vector<long long>> roads) {
    int n = (int)n_ll;

    // --- Step 1: Calculate minimum cost from any node to any other node (Empty Hand) ---
    // This is a standard All-Pairs Shortest Path (APSP) problem, but since weights are non-negative,
    // running Dijkstra from every node is appropriate.

