        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        // Note: tax_i is used for carrying, so for empty hand, we only use cost_i

        // Bidirectional road
        adj_empty[u].push_back({v, cost, 0}); 
        adj_empty[v].push_back({u, cost, 0});
    }

    // dist_empty[i][j] = minimum cost from i to j while carrying nothing
    vector<vector<long long>> dist_empty(n, vector<long long>(n, numeric_limits<long long>::max()));

    for (int start_node = 0; start_node < n; ++start_node) {
        // Dijkstra's Algorithm
        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;

        dist_empty[start_node][start_node] = 0;
        pq.push({0, start_node});

        while (!pq.empty()) {
            long long d = pq.top().first;
            int u = pq.top().second;
            pq.pop();

            if (d > dist_empty[start_node][u]) {
                continue;
            }

            for (const auto& edge : adj_empty[u]) {
                int v = edge.to;
                long long weight = edge.cost_no_apple; // For empty hand, cost = cost_i

                if (dist_empty[start_node][u] + weight < dist_empty[start_node][v]) {
                    dist_empty[start_node][v] = dist_empty[start_node][u] + weight;
                    pq.push({dist_empty[start_node][v], v});
                }
            }
        }
    }

    // --- Step 2: Calculate minimum cost from any node to any other node (Carrying Apple) ---
    // The cost for carrying is cost * tax.

    // Adj list for the "carrying" travel (cost = cost_i * tax_i)
    vector<vector<Edge>> adj_carrying(n);
    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        long long tax = road[3];

        long long carrying_cost = cost * tax;

        // Bidirectional road
        adj_carrying[u].push_back({v, carrying_cost, tax}); 
        adj_carrying[v].push_back({u, carrying_cost, tax});
    }

    // dist_carrying[i][j] = minimum cost from i to j while carrying an apple
    vector<vector<long long>> dist_carrying(n, vector<long long>(n, numeric_limits<long long>::max()));

    for (int start_node = 0; start_node < n; ++start_node) {
        // Dijkstra's Algorithm
        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;

        dist_carrying[start_node][start_node] = 0;
        pq.push({0, start_node});

        while (!pq.empty()) {
            long long d = pq.top().first;
            int u = pq.top().second;
            pq.pop();

            if (d > dist_carrying[start_node][u]) {
                continue;
            }

            for (const auto& edge : adj_carrying[u]) {
                int v = edge.to;
                long long weight = edge.cost_no_apple; // edge.cost_no_apple here stores the carrying cost

                if (dist_carrying[start_node][u] + weight < dist_carrying[start_node][v]) {
                    dist_carrying[start_node][v] = dist_carrying[start_node][u] + weight;
                    pq.push({dist_carrying[start_node][v], v});
                }
            }
        }
    }

    // --- Step 3: Calculate the final minimum cost for each store i ---
    vector<long long> ans(n);

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy at store i directly
        long long min_cost = prices[i];

        // Option 2: Go empty from i -> j (buy at j) -> i carrying
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Total cost = (i -> j empty) + prices[j] + (j -> i carrying)

            // Cost i -> j empty hand
            long long cost_go = dist_empty[i][j];

            // Cost j -> i carrying apple
            long long cost_return = dist_carrying[j][i];

            if (cost_go != numeric_limits<long long>::max() && cost_return != numeric_limits<long long>::max()) {
                long long total_cost = cost_go + prices[j] + cost_return;
                min_cost = min(min_cost, total_cost);
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}
