using namespace std;

// Structure to represent an edge
struct Edge {
    int to;
    long long cost_no_apple;
    long long tax_multiplier;
};

// Dijkstra's algorithm implementation
// Finds shortest paths from a source node (s) to all other nodes.
// Edge weight calculation depends on whether the traveler is carrying an apple.
// For path from s to t (empty hand): cost = sum(cost_no_apple)
// For path from s to t (with apple): cost = sum(cost_no_apple * tax_multiplier)
//
// Returns a pair: {dist_empty, dist_full} where:
// dist_empty[i]: shortest cost from s to i without apple.
// dist_full[i]: shortest cost from s to i with apple.
pair<vector<long long>, vector<long long>> dijkstra(
    int n, 
    const vector<vector<Edge>>& adj) {

    // Initialize distances. Use LLONG_MAX to represent infinity.
    const long long INF = numeric_limits<long long>::max();

    // dist_empty[i]: minimum cost to reach i from source without apple
    vector<long long> dist_empty(n, INF);
    // dist_full[i]: minimum cost to reach i from source with apple
    vector<long long> dist_full(n, INF);

    // Priority queue stores {distance, node}
    // Since we are finding shortest paths for two states (empty/full), 
    // we can use a state representation: {distance, node, is_full}
    // is_full = 0 for empty, is_full = 1 for full
    // Priority queue stores {distance, node, is_full} prioritized by distance (min-heap)
    using State = tuple<long long, int, int>;
    priority_queue<State, vector<State>, greater<State>> pq;

    // Start at node 0 (or any node, but for this problem, we need to run it multiple times if we wanted all-pairs)
    // Since we need shortest paths FROM *any* node j TO *any* node i (for empty/full segments), 
    // we need to calculate shortest paths for two scenarios:
    // 1. Empty -> j (Cost: cost_no_apple)
    // 2. j -> i (Cost: cost_no_apple * tax_multiplier)
    //
    // The problem is asking for:
    // ans[i] = min( prices[i], min_{j} ( SP_empty(i -> j) + prices[j] + SP_full(j -> i) ) )
    // Where SP_empty(i -> j) is the cost from i to j without apple.
    // And SP_full(j -> i) is the cost from j to i with apple.
    // Since roads are bidirectional, SP(u -> v) = SP(v -> u) using the same edge weights.
    //
    // Let's rephrase:
    // 1. Find min_cost_empty_to_j: Shortest path cost from any node i to node j without carrying apples.
    //    Since roads are bidirectional, this is equivalent to finding shortest path from j to i.
    // 2. Find min_cost_full_from_j: Shortest path cost from node j to any node i while carrying apples.
    //    Since roads are bidirectional, this is equivalent to finding shortest path from i to j.
    //
    // Given the structure of the problem, we need to calculate two sets of APSP (All-Pairs Shortest Path) or run Dijkstra N times.
    // Given N <= 1000, N*Dijkstra (O(N * E log V)) might be too slow if E is dense, but E <= 2000 is sparse.
    // N * E log N approx 1000 * 2000 * 10 = 2 * 10^7 operations, which is acceptable.
    //
    // We will modify Dijkstra to calculate SP from a *single source* `s`.

    // Initialize for source `s` (which will be passed in the main logic)
    // We run Dijkstra from a source `s` for the "empty" state and from a source `s` for the "full" state.
    // However, the interpretation of the path is critical:
    // 1. Go from i (empty) to j (empty) -> cost: SP_empty(i, j)
    // 2. Go from j (full) to i (full) -> cost: SP_full(j, i)

    // Let's run Dijkstra from ALL nodes j to find:
    // A. Min cost to reach j from any other node i, empty hand (Cost: cost_no_apple).
    // B. Min cost to reach j from any other node i, full hand (Cost: cost_no_apple * tax_multiplier).
    // Wait, the paths are: i --(empty)--> j --(full)--> i.

    // Path 1: i -> j (Empty Hand): Use cost_no_apple on all edges.
    // Path 2: j -> i (Full Hand): Use cost_no_apple * tax_multiplier on all edges.

    // Since roads are bidirectional, SP(A->B) = SP(B->A) using the respective edge costs.
    // Let's precalculate two distance matrices:
    // D_empty[u][v]: Shortest path cost from u to v using cost_no_apple.
    // D_full[u][v]: Shortest path cost from u to v using cost_no_apple * tax_multiplier.

    return {dist_empty, dist_full}; // This function signature is not useful for APSP directly.
}

// Implementation using Floyd-Warshall or N runs of Dijkstra for APSP
// Given N <= 1000 and E <= 2000, Dijkstra N times is safer if graph is sparse, but FW is simpler for dense/small graphs.
// Since E is small relative to N^2, N*Dijkstra is better.

// Dijkstra implementation adapted for a single source 'start_node'
// Edge weights depend on the state (empty/full).
vector<long long> dijkstra_single_source(int n, const vector<vector<Edge>>& adj, int start_node, bool is_full) {
    const long long INF = numeric_limits<long long>::max();
    vector<long long> dist(n, INF);

    dist[start_node] = 0;

    // Priority queue stores {distance, node}
    using State = pair<long long, int>;
    priority_queue<State, vector<State>, greater<State>> pq;
    pq.push({0, start_node});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();

        if (d > dist[u]) continue;

        for (const auto& edge : adj[u]) {
            int v = edge.to;
            long long weight;

            if (!is_full) {
                // Empty hand: weight = cost_i
                weight = edge.cost_no_apple;
            } else {
                // Full hand: weight = cost_i * tax_i
                weight = edge.cost_no_apple * edge.tax_multiplier;
            }

            if (dist[u] != INF && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}


std::vector<long long> solve(long long n_ll, std::vector<long long> prices, std::vector<std::vector<long long>> roads) {
    int n = (int)n_ll;

    // 1. Build Adjacency List
    vector<vector<Edge>> adj(n);
    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        long long tax = road[3];

        // Roads are bidirectional
        adj[u].push_back({v, cost, tax});
        adj[v].push_back({u, cost, tax});
    }

    // 2. Precompute Shortest Paths

    // D_empty[u][v]: Shortest path cost from u to v without apple (use cost_i)
    vector<vector<long long>> D_empty(n, vector<long long>(n));
    // D_full[u][v]: Shortest path cost from u to v with apple (use cost_i * tax_i)
    vector<vector<long long>> D_full(n, vector<long long>(n));

    // Calculate APSP by running Dijkstra from every node
    for (int s = 0; s < n; ++s) {
        // Calculate D_empty from s (i.e., SP from s to all j)
        vector<long long> dist_empty = dijkstra_single_source(n, adj, s, false);
        for (int j = 0; j < n; ++j) {
            D_empty[s][j] = dist_empty[j];
        }

        // Calculate D_full from s (i.e., SP from s to all j)
        vector<long long> dist_full = dijkstra_single_source(n, adj, s, true);
        for (int j = 0; j < n; ++j) {
            D_full[s][j] = dist_full[j];
        }
    }

    // Note on paths:
    // We need: i --(empty)--> j AND j --(full)--> i
    // D_empty[i][j] = SP(i -> j, empty)
    // D_full[j][i] = SP(j -> i, full)

    // 3. Calculate Final Answer ans[i]
    vector<long long> ans(n);
    const long long INF = numeric_limits<long long>::max();

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at shop i
        long long min_cost = prices[i];

        // Option 2: Go empty to shop j, buy at j, return full to i
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Cost to go empty from i to j: D_empty[i][j]
            long long cost_empty = D_empty[i][j];

            // Cost to return full from j to i: D_full[j][i]
            long long cost_full = D_full[j][i];

            if (cost_empty != INF && cost_full != INF) {
                // Total cost = Cost(i->j empty) + Price(j) + Cost(j->i full)
                // Since we are using long long for prices, we must check for overflow before adding, 
                // though with constraints (10^9 * 100 * 1000) it should fit in long long.
                long long current_total_cost = cost_empty + prices[j] + cost_full;
                min_cost = min(min_cost, current_total_cost);
            }
        }

        ans[i] = min_cost;
    }

    return ans;
}
