// Structure to hold adjacency list for one mode of travel (Empty or Full)
struct Graph {
    int n;
    vector<vector<pair<int, long long>>> adj; // {to, weight}

    Graph(int n_nodes) : n(n_nodes) {
        adj.resize(n);
    }

    void add_edge(int u, int v, long long weight) {
        adj[u].push_back({v, weight});
        adj[v].push_back({u, weight}); // Bidirectional
    }

    // Single Source Shortest Path using Dijkstra
    vector<long long> dijkstra(int start_node) {
        vector<long long> dist(n, INF);
        dist[start_node] = 0;

        // Min-heap: {distance, node}
        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
        pq.push({0, start_node});

        while (!pq.empty()) {
            long long d = pq.top().first;
            int u = pq.top().second;
            pq.pop();

            if (d > dist[u]) continue;

            for (const auto& edge : adj[u]) {
                int v = edge.first;
                long long weight = edge.second;

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.push({dist[v], v});
                }
            }
        }
        return dist;
    }
};


vector<long long> solve(long long n, vector<long long> prices, vector<vector<long long>> roads) {
    int N = (int)n;

    // d_empty[i][j]: shortest path cost from i to j while empty-handed
    vector<vector<long long>> d_empty(N, vector<long long>(N, INF));
    // d_full[i][j]: shortest path cost from i to j while carrying apples
    vector<vector<long long>> d_full(N, vector<long long>(N, INF));

    // 1. Build graphs for empty and full travel

    // Graph for empty travel (cost_i)
    Graph graph_empty(N);
    // Graph for full travel (cost_i * tax_i)
    Graph graph_full(N);

    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        long long tax = road[3];

        // Empty travel cost
        graph_empty.add_edge(u, v, cost);

        // Full travel cost
        long long full_cost = cost * tax;
        graph_full.add_edge(u, v, full_cost);
    }

    // 2. Compute All-Pairs Shortest Paths (APSP) using N Dijkstra runs

    // Compute d_empty[i][j] for all i, j
    for (int i = 0; i < N; ++i) {
        vector<long long> dists = graph_empty.dijkstra(i);
        for (int j = 0; j < N; ++j) {
            d_empty[i][j] = dists[j];
        }
    }

    // Compute d_full[i][j] for all i, j
    for (int i = 0; i < N; ++i) {
        vector<long long> dists = graph_full.dijkstra(i);
        for (int j = 0; j < N; ++j) {
            d_full[i][j] = dists[j];
        }
    }

    // 3. Calculate the minimum total cost for each store i
    vector<long long> ans(N);

    for (int i = 0; i < N; ++i) {
        // Option 1: Buy at store i directly
        long long min_cost = prices[i];

        // Option 2: Buy at store j, travel empty i -> j, then travel full j -> i
        for (int j = 0; j < N; ++j) {
            if (i == j) continue;

            // Total Cost = Price[j] + Travel_Empty(i -> j) + Travel_Full(j -> i)

            long long cost_empty_ij = d_empty[i][j];
            long long cost_full_ji = d_full[j][i];

            // If either path is unreachable, skip this j
            if (cost_empty_ij == INF || cost_full_ji == INF) {
                continue;
            }

            // Total Cost = Price[j] + Cost(i->j, empty) + Cost(j->i, full)
            long long current_total_cost = prices[j] + cost_empty_ij + cost_full_ji;

            min_cost = min(min_cost, current_total_cost);
        }

        ans[i] = min_cost;
    }

    return ans;
